class Solution:
  def solve(self, s: str) -> bool:
    exposedPorts = set()
    containerPortMappings = set()

    services = s.split('\n')

    for i in range(len(services)):
      if services[i].startswith('ports:'): 
        ports = services[i].split('  \n')
        for j in range(len(ports)):
          portMapping = ports[j].split(':')
          if portMapping[0].startswith(' '):
            exposedPorts.add(portMapping[0].strip())
          else:
            port = portMapping[0].split(':')[0]
            containerPort = portMapping[0].split(':')[1]
            if port in exposedPorts or port in containerPortMappings:
              return False
            containerPortMappings.add(port)

    return True
